.forge-hero {background:var(--s2a-color-gray-1000);color:var(--s2a-color-gray-25);--text-color:var(--s2a-color-gray-25)}

.forge-hero main > section.hero {padding:var(--s2a-layout-lg) 8.333%}

.forge-hero .inner {max-width:1440px;margin:0 auto;width:100%}

.forge-hero .con-button {
    background-color:transparent;
    border-radius:16px;
    border:2px solid var(--text-color);
    color:var(--text-color);
    display:inline-block;
    font-size:15px;
    font-weight:700;
    line-height:16px;
    padding:5px 14px;
    text-decoration:none;
  }

.forge-hero .con-button:hover {
    background-color:var(--s2a-color-gray-1000);
    border-color:var(--s2a-color-gray-1000);
    color:var(--s2a-color-gray-25);
    text-decoration:none;
  }

.forge-hero .con-button.button-l {border-radius:20px;font-size:17px;line-height:20px;padding:7px 18px 8px}

.forge-hero .con-button.button-xl {border-radius:25px;font-size:19px;line-height:24px;padding:10px 24px 8px}

.forge-hero .con-button.button-xxl {border-radius:30px;font-size:22px;line-height:27px;padding:14px 30px 15px}

.forge-hero .con-button {border-color:var(--s2a-color-gray-25);color:var(--s2a-color-gray-25)}

.forge-hero .light .con-button {border-color:var(--text-color);color:var(--text-color)}

.forge-hero .con-button:hover {background-color:var(--s2a-color-gray-25);border-color:var(--s2a-color-gray-25);color:var(--s2a-color-gray-1000)}

.forge-hero .light .con-button:hover {background-color:var(--s2a-color-gray-1000);border-color:var(--s2a-color-gray-1000);color:var(--s2a-color-gray-25)}

.forge-hero .cta-row {display:flex;gap:var(--s2a-spacing-16);flex-wrap:wrap;align-items:center;margin-top:var(--s2a-spacing-32)}

.forge-hero .cta-row p {margin:0}

.forge-hero .eyebrow {
    display:inline-block;
    font-size:13px;font-weight:700;letter-spacing:.08em;text-transform:uppercase;
    margin-bottom:var(--s2a-spacing-16);
    color:var(--text-color);
  }

.forge-hero .eyebrow .dot {display:inline-block;width:8px;height:8px;border-radius:50%;background:var(--s2a-color-brand-adobe-red);margin-right:var(--s2a-spacing-8);vertical-align:middle}

.forge-hero {width:100%}

.forge-hero .content {max-width:900px}

.forge-hero .content {margin:0 auto;text-align:center}

.forge-hero .content {max-width:820px}

.forge-hero h1 {font-size:var(--s2a-font-size-64);letter-spacing:-.03em;margin-bottom:var(--s2a-spacing-24)}

.forge-hero h2 {font-size:var(--s2a-font-size-48);margin-bottom:var(--s2a-spacing-24)}

.forge-hero .body-lg {font-size:var(--s2a-font-size-20);line-height:1.6;max-width:620px}

.forge-hero .body-lg {margin-left:auto;margin-right:auto}

.forge-hero .trust {margin-top:var(--s2a-spacing-24);font-size:14px;color:var(--s2a-color-gray-500)}

.forge-hero {position:relative;overflow:hidden}

.forge-hero .hero-bg {position:absolute;inset:0;z-index:0}

.forge-hero .hero-bg picture, .forge-hero .hero-bg img {width:100%;height:100%;object-fit:cover;display:block}

.forge-hero .inner {position:relative;z-index:1}

.forge-hero .band-head .inner {max-width:1440px;margin:0 auto;text-align:center}

.forge-hero .columns .inner {display:grid;grid-template-columns:repeat(3,1fr);gap:var(--s2a-spacing-24)}

